const outputAgente = $input.first().json.output;

const resultado = {
  status: outputAgente.status || 'unknown',
  file_name: outputAgente.file_name || '',
  content: outputAgente.content || '',
  changes: outputAgente.changes
};

return [{
  json: resultado
}];

const input = $input.first().json;
const body = input.body || input;

const folderPath = body.folder_path || '';
const configFiles = body.files || [];

const items = configFiles.map(filename => ({
    json: {
        config_file: filename,
        folder_path: folderPath
    }
}));

return items;

const input = $input.first().json;
const fileContent = input.stdout || '';

return [{
    json: {
        config_content: fileContent,
        config_file: $('Code in JavaScript17').first().json.config_file,
    }
}];

const input = $input.first().json;

const folderPath = input.folder_path || '';
const configFile = input.config_file || '';

const comando = `type "${folderPath}\\${configFile}"`;

return [{
    json: {
        ...input,
        comando: comando
    }
}];

const pyItem = $input.all()[0].json;
const questionItem = $input.all()[1].json;

// Extraer datos
const fileName = pyItem.config_file;
const fileContent = pyItem.config_content;
const question = questionItem.config_content;

const combinedOutput = {
  file_name: fileName,
  file_content: fileContent,
  question: question
}

return combinedOutput;
